# 三、我建议改完后的灾备段逻辑

大概会变成这样：

```bash
# 13) 大脑灾备自动同步（失败不阻断）
echo -e "\n[13/13] 大脑灾备 (Git Backup)" >> "$REPORT_FILE"
BACKUP_STATUS=""

if git -C "$OC" rev-parse --is-inside-work-tree >/dev/null 2>&1; then
  if git -C "$OC" remote get-url origin >/dev/null 2>&1; then
    if git -C "$OC" add . >> "$REPORT_FILE" 2>&1; then
      if git -C "$OC" diff --cached --quiet; then
        echo "No staged changes" >> "$REPORT_FILE"
        BACKUP_STATUS="skip"
      else
        if git -C "$OC" commit -m "🛡️ Nightly brain backup ($DATE_STR)" >> "$REPORT_FILE" 2>&1; then
          if git -C "$OC" push origin main >> "$REPORT_FILE" 2>&1; then
            BACKUP_STATUS="ok"
          else
            BACKUP_STATUS="push_fail"
          fi
        else
          BACKUP_STATUS="commit_fail"
        fi
      fi
    else
      BACKUP_STATUS="add_fail"
    fi
  else
    BACKUP_STATUS="no_remote"
  fi
else
  BACKUP_STATUS="git_broken"
fi
```

然后汇总改成：

```bash
case "$BACKUP_STATUS" in
  ok)          SUMMARY+="13. 灾备备份: ✅ 已自动推送至远端仓库\n" ;;
  skip)        SUMMARY+="13. 灾备备份: ✅ 无新变更，跳过推送\n" ;;
  git_broken)  append_warn "13. 灾备备份: ⚠️ Git仓库无效或元数据损坏" ;;
  no_remote)   append_warn "13. 灾备备份: ⚠️ Git仓库存在，但未配置 origin" ;;
  add_fail)    append_warn "13. 灾备备份: ⚠️ git add 失败（详见详细报告）" ;;
  commit_fail) append_warn "13. 灾备备份: ⚠️ git commit 失败（详见详细报告）" ;;
  push_fail)   append_warn "13. 灾备备份: ⚠️ git push 失败（详见详细报告）" ;;
  *)           append_warn "13. 灾备备份: ⚠️ 未知异常（详见详细报告）" ;;
esac
```

